queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?lab_equipments a :Lab_Equipments .
    ?lab_equipments p:equipName ?equipname .
    BIND(?equipname AS ?o0)
  }
  UNION
  {
    ?safety_gears a :Safety_Gears .
    ?safety_gears p:gearName ?gearname .
    ?safety_gears p:dateOfPurchase ?dateofpurchase_f .
    FILTER(STR(?dateofpurchase_f) = "January 2023")
    BIND(?gearname AS ?o0)
  }
}

